queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?level WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCourse_Levels ?child ; p:hasLanguage_Schools ?parent . } GROUP BY ?child }
  ?child p:level ?level .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Language_Schools } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?level WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCourse_Levels ?child ; p:hasLanguage_Schools ?parent . } GROUP BY ?child }
  ?child p:level ?level .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Language_Schools } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?level WHERE {
  ?language_schools_course_levels a :Language_Schools_Course_Levels .
  ?course_levels a :Course_Levels .
  ?language_schools_course_levels p:hasCourse_Levels ?course_levels .
  ?language_schools a :Language_Schools .
  ?language_schools_course_levels p:hasLanguage_Schools ?language_schools .
  ?language_schools p:name ?name .
  ?course_levels p:level ?level .
} }
}
